2106: func (api *API) respond(w http.ResponseWriter, req *http.Request, data any, warnings annotations.Annotations, query string) {
2107: 	statusMessage := statusSuccess
2108: 	warn, info := warnings.AsStrings(query, 10, 10)
2109: 
2110: 	resp := &Response{
2111: 		Status:   statusMessage,
2112: 		Data:     data,
2113: 		Warnings: warn,
2114: 		Infos:    info,
2115: 	}
2116: 
2117: 	codec, err := api.negotiateCodec(req, resp)
2118: 	if err != nil {
2119: 		api.respondError(w, &apiError{errorNotAcceptable, err}, nil)
2120: 		return
2121: 	}
2122: 
2123: 	b, err := codec.Encode(resp)
2124: 	if err != nil {
2125: 		api.logger.Error("error marshaling response", "url", req.URL, "err", err)
2126: 		http.Error(w, err.Error(), http.StatusInternalServerError)
2127: 		return
2128: 	}
2129: 
2130: 	w.Header().Set("Content-Type", codec.ContentType().String())
2131: 	w.WriteHeader(http.StatusOK)
2132: 	if n, err := w.Write(b); err != nil {
2133: 		api.logger.Error("error writing response", "url", req.URL, "bytesWritten", n, "err", err)
2134: 	}
2135: }
