2137: func (api *API) negotiateCodec(req *http.Request, resp *Response) (Codec, error) {
2138: 	for _, clause := range goautoneg.ParseAccept(req.Header.Get("Accept")) {
2139: 		for _, codec := range api.codecs {
2140: 			if codec.ContentType().Satisfies(clause) && codec.CanEncode(resp) {
2141: 				return codec, nil
2142: 			}
2143: 		}
2144: 	}
2145: 
2146: 	defaultCodec := api.codecs[0]
2147: 	if !defaultCodec.CanEncode(resp) {
2148: 		return nil, fmt.Errorf("cannot encode response as %s", defaultCodec.ContentType())
2149: 	}
